#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,dp[5001],a[5001],ans=1;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    dp[1]=1;
    for(int i=2;i<=n;i++){
        dp[i]=1;
        for(int j=1;j<i;j++){
            if(a[j]<a[i])dp[i]=max(dp[i],dp[j]+1);
        }
        ans=max(ans,dp[i]);
    }
    cout<<ans;
    return 0;
}
